const axios = require('axios');

const config = $('Code - Fetch Board Config').first().json;
const { conversation_id, company_id, ai_prompt, instance_name, phone, content_text } = config;

const SUPA_URL = 'https://fhkhamwrfwtacwydukvb.supabase.co';
const SUPA_KEY = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6ImZoa2hhbXdyZnd0YWN3eWR1a3ZiIiwicm9sZSI6InNlcnZpY2Vfcm9sZSIsImlhdCI6MTc2NTMyNjcxMywiZXhwIjoyMDgwOTAyNzEzfQ.slNbow0lzBpryTaPPNNPDOV5x_uBqRHQZR38RRk92sY';
const EVO_URL = 'https://easypanel.julianosalles.com.br';
const EVO_KEY = '4DD73F0CC46E-407C-B70D-48C9175EC89B';
const OPENAI_KEY = 'sk-CONFIGURE_SUA_CHAVE_OPENAI_AQUI';

const supaH = { apikey: SUPA_KEY, Authorization: 'Bearer ' + SUPA_KEY, 'Content-Type': 'application/json' };

const histRes = await axios.get(SUPA_URL + '/rest/v1/messages?conversation_id=eq.' + conversation_id + '&company_id=eq.' + company_id + '&order=sent_at.desc&limit=8', { headers: supaH });
const histData = histRes.data;

const chatHistory = (Array.isArray(histData) ? histData : [])
  .slice(1).reverse()
  .map(function(m) { return { role: m.sender_type === 'lead' ? 'user' : 'assistant', content: (m.content || '').trim() }; })
  .filter(function(m) { return m.content; });

const systemPrompt = (ai_prompt || '').trim() || 'Voce e um assistente de vendas profissional e cordial. Responda sempre em portugues brasileiro.';

const messages = [{ role: 'system', content: systemPrompt }].concat(chatHistory).concat([{ role: 'user', content: content_text }]);
const aiRes = await axios.post('https://api.openai.com/v1/chat/completions', { model: 'gpt-4o-mini', messages: messages, max_tokens: 500, temperature: 0.7 }, { headers: { Authorization: 'Bearer ' + OPENAI_KEY, 'Content-Type': 'application/json' } });

const choice = aiRes.data.choices && aiRes.data.choices[0];
const aiText = choice && choice.message && choice.message.content ? choice.message.content.trim() : null;
if (!aiText) return [{ json: { ok: false, error: 'openai_no_response', detail: aiRes.data } }];

const instanceEncoded = encodeURIComponent(instance_name);
await axios.post(EVO_URL + '/message/sendText/' + instanceEncoded, { number: phone + '@s.whatsapp.net', text: aiText }, { headers: { apikey: EVO_KEY, 'Content-Type': 'application/json' } });

await axios.post(SUPA_URL + '/rest/v1/rpc/insert_message', { p_company_id: company_id, p_conversation_id: conversation_id, p_external_message_id: 'agent-' + Date.now(), p_direction: 'outbound', p_sender_type: 'agent', p_content: aiText, p_content_type: 'text', p_sent_at: new Date().toISOString(), p_media_url: null, p_metadata: {} }, { headers: supaH });

return [{ json: { ok: true, ai_response: aiText } }];
